class Solution:
    def findTheLongestBalancedSubstring(self, s: str) -> int:
        max_len = 0
        for i in range(len(s)):
            zeros = 0
            for j in range(i, len(s)):
                if s[j] == '0':
                    zeros += 1
                else:
                    if zeros > 0:
                        zeros -= 1
                    else:
                        break
                if zeros == 0:
                    max_len = max(max_len, j - i + 1)
        return max_len
